var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"바이크를 쫓아오다니 제법인걸?","JPN":"バイクのスピードに追いつくとはやるね。","ENG":"I'm impressed you're able to catch up when I'm on my bike.","TWN":"竟然追上來了，不錯喔？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"못 도망친다.","JPN":"逃ガサナイ。","ENG":"You cannot run away.","TWN":"你逃不了的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"시간… 낭비일 뿐.","JPN":"時間ノ……無駄ダ。","ENG":"Waste... of time.","TWN":"只是浪費時間而已……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"시간? 침식체가 재미있는 단어를 쓰네.","JPN":"時間？　侵食体のくせに、面白い単語を使うね。","ENG":"Time? Funny hearing that word coming from a C.O.","TWN":"時間？侵蝕體竟然也會說這種詞？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼 수류탄이란 것도 들어 봤어?","JPN":"じゃあ、手榴弾っていう言葉も知ってるのかな？","ENG":"Then, have you ever heard of the words, \\"hand grenade?\\"","TWN":"那你聽說過手榴彈嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하, 아슬아슬했군. 거의 따라 잡힐 뻔했어.","JPN":"はぁ、ぎりぎりだった。もうすこしで追いつかれるところだったよ。","ENG":"*Sigh.* That was a close one. He almost got me.","TWN":"哈，好險，差點就被你抓住了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…통신기는 여기서도 먹통인가?","JPN":"……通信機はここでも使えないのかな？","ENG":"...Are the comms down here too?","TWN":"……通訊器又失靈了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"큭…?!","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"呃……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_09"},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"침식체가 매복이라고?","JPN":"侵食体が待ち伏せだと？","ENG":"A C.O. ambush?!","TWN":"侵蝕體竟然會埋伏？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하아… 정말.","JPN":"はあ……まったく。","ENG":"*Sigh...* Really?","TWN":"呼……真是的。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"바람 쐰다더니 얼마나 멀리 간 거야?","JPN":"息抜きにどこまで行ったんだ？","ENG":"How far did she go to get fresh air?","TWN":"不是說要去透透氣嗎？是跑多遠？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래, 크리스. 소리에 집중해보자… 집중…","JPN":"そうよ、クリス。音に集中して……集中……","ENG":"Okay, Chris. Focus on the sounds... Focus...","TWN":"好了，克莉絲。注意聽聲音……專注……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이건… 희미한 모터 소리…?","JPN":"これは……微かに聞こえる、モーターの音……？","ENG":"That's... a faint motor sound...?","TWN":"那是……微弱的引擎聲……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨… 설마 혼자 바이크 타고 시내까지 가버린 건 아니겠지?","JPN":"レアさん……まさか、一人でバイクに乗って街まで行ったんじゃないよね？","ENG":"Leah... You didn't go out to town on your motorcycle, did you?","TWN":"蕾亞……該不會一個人騎車跑到市區了吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐익?!!","JPN":"ひいっ！？","ENG":"Heek?!!","TWN":"啊？！！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아야야, 집중하다 귀청 떨어질 뻔했네.","JPN":"いてて、集中してたのに、鼓膜が破れるかと思ったじゃん。","ENG":"Oww... I almost went deaf, trying to focus too hard.","TWN":"啊啊啊，耳朵差點被震壞了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식체…?! 얼른 숨어야 해!","JPN":"侵食体……！？　早く隠れなきゃ！","ENG":"C.O.s...?! I need to hide!","TWN":"侵蝕體……？快躲起來！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"큰일이네. <color=#ffd34c>장비</color>는 전부 관리국 무기고에 맡겨 뒀는데.","JPN":"参ったな。 <color=#ffd34c>装備</color>は全部、管理局の武器倉庫に預けてきたのに。","ENG":"This isn't good. All my <color=#ffd34c>gear</color> is in the Administration's armory.","TWN":"不好了。我把所有<color=#ffd34c>裝備</color>都留在了管理局的武器庫。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데… 내 착각인가?","JPN":"それにしても……私の勘違いかな？","ENG":"But... is it just my imagination?","TWN":"但是……是我的錯覺嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"왜 사람한테 별 관심이 없는 것처럼 보이지?","JPN":"なんで人に関心がないように見えるんだろ？","ENG":"Why do they look like they're not interested in people?","TWN":"他為什麼看起來對人類毫無興趣？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"게다가 저 녀석들이 향하는 방향은… 방금 모터 소리가 들리던 방향이야.","JPN":"しかも侵食体が向かっている方向って……今、モーターの音がした方向だよね。","ENG":"On top of that, they're headed toward... where I heard the motor sound.","TWN":"他們前進的方向……就是我們剛才聽到引擎聲的方向。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"일단 도망칠까? 레아 씨라면 이미 안전한 곳에 있을지도 모르는데.","JPN":"取りあえず逃げようか？　レアさんなら既に安全な場所にいるかもしれないし。","ENG":"Should I make a run for it? Maybe Leah has already found a safe place to hide.","TWN":"要先逃跑嗎？蕾亞可能已經抵達安全的地方了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 저런 녀석들이 레아 씨를 쫓고 있다고 상상하면…","JPN":"でも、侵食体がレアさんを追いかけていると思うと……","ENG":"But, to think that they might be chasing Leah...","TWN":"但試想一下，如果他們的目標是蕾亞……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…으윽, 정말. 찾아보는 수밖에 없잖아.","JPN":"……もうっ、まったく。探すしかないじゃない。","ENG":"...Ngh, sheesh. Now I have to go look for her.","TWN":"……唉，真是的，我得去查查。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};